// Pull both forall ensures into the proof context so their (otherwise
// disjoint) triggers line up via the shared `pre_self_.page_array@[i]`
// pattern. These re-assertions are not assumptions — Verus must
// re-derive them from the ensures clauses already in scope.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: at every valid index, post1's and post2's pages agree.
// Case split on whether i hits the modified slot or not.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At the modified index, the per-field ensures pin every component
        // of page_array@[index] to either the corresponding pre_self_
        // component (addr, state, is_io_page, rev_pointer, owning_container,
        // mappings, io_mappings) or to the input parameter `ref_count`.
        // Both runs therefore produce a Page with identical fields, hence
        // =~= holds by struct extensionality.
    } else {
        // Off the modified index, the two forall ensures (just re-asserted)
        // pin both post1_self_.page_array@[i] and post2_self_.page_array@[i]
        // to pre_self_.page_array@[i], so they are =~= by transitivity.
    }
}

// Sequence extensionality lifts the pointwise equality to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
